import{c as e,Q as d,j as r,m as a}from"./chunks/framework.CdiUUa3G.js";const g=JSON.parse('{"title":"Orrery i18n Style Guide","description":"","frontmatter":{},"headers":[],"relativePath":"i18n-style-guide.md","filePath":"i18n-style-guide.md"}'),n={name:"i18n-style-guide.md"};function o(i,t,s,l,c,h){return d(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="orrery-i18n-style-guide" tabindex="-1">Orrery i18n Style Guide <a class="header-anchor" href="#orrery-i18n-style-guide" aria-label="Permalink to &quot;Orrery i18n Style Guide&quot;">​</a></h1><p><em>Translator brief — applies to every language. v0.1 · May 2026</em></p><blockquote><p>Required reading before translating any locale. Authority for terminology decisions; updates here trigger re-translation of affected files (per ADR-033 §implementation-notes).</p></blockquote><hr><h2 id="how-to-use-this-guide" tabindex="-1">How to use this guide <a class="header-anchor" href="#how-to-use-this-guide" aria-label="Permalink to &quot;How to use this guide&quot;">​</a></h2><p>You are translating Orrery into a new language. Before you start:</p><ol><li>Read <strong>§1 Universal symbols</strong> — these are never translated. Use the symbol literally in every language.</li><li>Read <strong>§2 Proper nouns</strong> — transliterate per local convention only; do not translate.</li><li>Use <strong>§3 + §4</strong> as a binding glossary. The accepted-convention column for your language is the source of truth; pick from the column rather than translating the English literally.</li><li>If your language column is empty (you&#39;re the first translator for it), populate it as you go and submit those decisions for review with the translation pass.</li><li><strong>Citation column</strong> points at the source authority for the term (ESA glossary, NASA Spanish-language style guide, JAXA glossary, etc.). Cite where possible; defer to authoritative sources over LLM judgement.</li></ol><p>Files you will be touching:</p><ul><li><code>messages/&lt;code&gt;.json</code> — Paraglide UI strings (~276 keys; informal register where the en-US source uses a friendly tone).</li><li><code>static/data/i18n/&lt;code&gt;/missions/{mars,moon}/*.json</code> — 36 mission overlay files. Translate <code>name</code> (display name), <code>description</code>, <code>first</code> (claim-to-fame), <code>type</code> (e.g. <code>LANDER · FLOWN</code>), <code>events[].label</code>, <code>events[].note</code>. Keep mission <code>id</code> and proper nouns intact.</li><li><code>static/data/i18n/&lt;code&gt;/{planets,rockets,sun,scenarios,earth-objects,moon-sites}/*.json</code> — same overlay pattern, smaller files.</li></ul><p>Per ADR-017&#39;s fallback chain, any key you omit will fall back to en-US — broken translation is bounded, not user-blocking.</p><hr><h2 id="§1-universal-symbols-never-translated" tabindex="-1">§1 Universal symbols (NEVER translated) <a class="header-anchor" href="#§1-universal-symbols-never-translated" aria-label="Permalink to &quot;§1 Universal symbols (NEVER translated)&quot;">​</a></h2><p>These render as the symbol in every language. A native-language gloss is allowed <em>on first use only</em> if helpful for non-technical readers.</p><table tabindex="0"><thead><tr><th>Symbol</th><th>What it means</th><th>Notes</th></tr></thead><tbody><tr><td><code>Δv</code> (delta-v)</td><td>Change in velocity, the standard mission-energy budget</td><td>Universal across every space agency&#39;s literature</td></tr><tr><td><code>Isp</code></td><td>Specific impulse (rocket engine efficiency)</td><td>Universal abbreviation; spelled out as needed in editorial prose</td></tr><tr><td><code>C₃</code></td><td>Characteristic energy (escape-trajectory energy)</td><td>Universal symbol</td></tr><tr><td><code>AU</code></td><td>Astronomical Unit</td><td>English / Japanese / Mandarin use <code>AU</code>; Spanish / French / Portuguese / Italian use <code>UA</code>; document per-language column below</td></tr><tr><td><code>g</code></td><td>Earth surface gravity (9.81 m/s²)</td><td>Universal</td></tr></tbody></table><p>Numeric units (km, s, kg, N, K, etc.) are <strong>never translated</strong> — they are SI. Number <em>formatting</em> (1,000.5 vs 1.000,5) is handled by <code>Intl.NumberFormat</code> and is automatic per locale; translators never format numbers in strings.</p><hr><h2 id="§2-proper-nouns-transliterate-only-—-never-translate" tabindex="-1">§2 Proper nouns (TRANSLITERATE only — never translate) <a class="header-anchor" href="#§2-proper-nouns-transliterate-only-—-never-translate" aria-label="Permalink to &quot;§2 Proper nouns (TRANSLITERATE only — never translate)&quot;">​</a></h2><h3 id="scientist-surnames-transliterate-per-language-convention" tabindex="-1">Scientist surnames (transliterate per language convention) <a class="header-anchor" href="#scientist-surnames-transliterate-per-language-convention" aria-label="Permalink to &quot;Scientist surnames (transliterate per language convention)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>English</th><th>Notes</th></tr></thead><tbody><tr><td>Hohmann (transfer)</td><td>Walter Hohmann</td></tr><tr><td>Tsiolkovsky (equation)</td><td>Konstantin Tsiolkovsky</td></tr><tr><td>Lagrange (point, L1–L5)</td><td>Joseph-Louis Lagrange</td></tr><tr><td>Lambert (problem, solver)</td><td>Johann Heinrich Lambert</td></tr><tr><td>Kepler (laws, orbit)</td><td>Johannes Kepler</td></tr><tr><td>Oberth (effect)</td><td>Hermann Oberth</td></tr><tr><td>Newton (laws, units)</td><td>Isaac Newton</td></tr></tbody></table><h3 id="mission-proper-nouns-keep-in-original-—-do-not-translate-or-transliterate" tabindex="-1">Mission proper nouns (KEEP IN ORIGINAL — do not translate or transliterate) <a class="header-anchor" href="#mission-proper-nouns-keep-in-original-—-do-not-translate-or-transliterate" aria-label="Permalink to &quot;Mission proper nouns (KEEP IN ORIGINAL — do not translate or transliterate)&quot;">​</a></h3><p>Rationale: missions are real-world objects with single canonical names. A user searching for &quot;Curiosity&quot; in Spanish documentation should still find &quot;Curiosity&quot;, not &quot;Curiosidad&quot;.</p><table tabindex="0"><thead><tr><th>Mission</th><th>Original</th></tr></thead><tbody><tr><td>All NASA Mars rovers</td><td>Curiosity, Perseverance, Sojourner, Spirit, Opportunity (English; keep)</td></tr><tr><td>Apollo programme</td><td>Apollo 11, Apollo 17, Artemis II, Artemis III (keep numerals + name)</td></tr><tr><td>ISRO</td><td>Chandrayaan-1, Chandrayaan-3, Mangalyaan / Mars Orbiter Mission (keep both names where dual-named)</td></tr><tr><td>CNSA</td><td>Tianwen-1, Chang&#39;e 4 / 5 / 6 (keep apostrophes + numerals)</td></tr><tr><td>JAXA</td><td>Hayabusa, SLIM (keep romanisation)</td></tr><tr><td>Roscosmos</td><td>Luna 9 / 17 / 24, Mars 3 (keep)</td></tr><tr><td>ESA</td><td>Mars Express (keep)</td></tr><tr><td>MBRSC (UAE)</td><td>Hope Probe (keep English; &quot;مسبار الأمل&quot; is acceptable in Arabic editorial prose only)</td></tr><tr><td>SpaceX</td><td>Starship (keep)</td></tr><tr><td>Blue Origin</td><td>Blue Moon MK1 (keep)</td></tr><tr><td>Tito concept</td><td>Inspiration Mars (keep)</td></tr></tbody></table><h3 id="agency-proper-nouns-keep-in-original-acronym" tabindex="-1">Agency proper nouns (KEEP IN ORIGINAL acronym) <a class="header-anchor" href="#agency-proper-nouns-keep-in-original-acronym" aria-label="Permalink to &quot;Agency proper nouns (KEEP IN ORIGINAL acronym)&quot;">​</a></h3><p>NASA, ESA, JAXA, ISRO, CNSA, ROSCOSMOS, UAESA, AEB, KARI, CSA, UKSA, ASI, DLR, CNES, MBRSC. Do <strong>not</strong> expand or translate the acronyms.</p><hr><h2 id="§3-translatable-astronomy-orbital-mechanics-terms" tabindex="-1">§3 Translatable astronomy + orbital-mechanics terms <a class="header-anchor" href="#§3-translatable-astronomy-orbital-mechanics-terms" aria-label="Permalink to &quot;§3 Translatable astronomy + orbital-mechanics terms&quot;">​</a></h2><p>The English column is the source. The accepted-convention column for your target language is the <strong>binding</strong> translation. Cite source where given.</p><table tabindex="0"><thead><tr><th>English</th><th><code>es</code> (Spanish)</th><th><code>fr</code></th><th><code>de</code></th><th><code>pt-BR</code></th><th><code>it</code></th><th><code>sr-Latn</code></th><th><code>sr-Cyrl</code></th><th>Source</th></tr></thead><tbody><tr><td>aphelion</td><td>afelio</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>RAE</td></tr><tr><td>perihelion</td><td>perihelio</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>RAE</td></tr><tr><td>apogee</td><td>apogeo</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>RAE</td></tr><tr><td>perigee</td><td>perigeo</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>RAE</td></tr><tr><td>eccentricity</td><td>excentricidad</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>RAE</td></tr><tr><td>true anomaly</td><td>anomalía verdadera</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>ESA Spanish glossary</td></tr><tr><td>line of apsides</td><td>línea de los ápsides</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>ESA Spanish glossary</td></tr><tr><td>free-return (trajectory)</td><td>trayectoria de retorno libre</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>NASA-MSFC Spanish</td></tr><tr><td>sphere of influence (SOI)</td><td>esfera de influencia</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>ESA Spanish glossary</td></tr><tr><td>porkchop plot</td><td>diagrama porkchop <em>(no Spanish equivalent in wide use)</em></td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>ESA Spanish glossary uses English</td></tr><tr><td>Astronomical Unit (AU / UA)</td><td>UA (unidad astronómica)</td><td>UA</td><td>AE (Astronomische Einheit)</td><td>UA</td><td>UA</td><td>—</td><td>—</td><td>IAU</td></tr></tbody></table><p>Empty cells are populated by the translator for that language ticket.</p><hr><h2 id="§4-translatable-mission-domain-terms" tabindex="-1">§4 Translatable mission-domain terms <a class="header-anchor" href="#§4-translatable-mission-domain-terms" aria-label="Permalink to &quot;§4 Translatable mission-domain terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>English</th><th><code>es</code></th><th><code>fr</code></th><th><code>de</code></th><th><code>pt-BR</code></th><th><code>it</code></th><th>Source</th></tr></thead><tbody><tr><td>launch window</td><td>ventana de lanzamiento</td><td>—</td><td>—</td><td>—</td><td>—</td><td>NASA-JPL Spanish</td></tr><tr><td>transit (cruise phase)</td><td>tránsito</td><td>—</td><td>—</td><td>—</td><td>—</td><td>ESA Spanish</td></tr><tr><td>flyby</td><td>sobrevuelo</td><td>—</td><td>—</td><td>—</td><td>—</td><td>ESA Spanish</td></tr><tr><td>orbit insertion</td><td>inserción orbital</td><td>—</td><td>—</td><td>—</td><td>—</td><td>ESA Spanish</td></tr><tr><td>LOI (lunar orbit insertion)</td><td>inserción en órbita lunar (IOL)</td><td>—</td><td>—</td><td>—</td><td>—</td><td>NASA-MSFC Spanish</td></tr><tr><td>MOI (Mars orbit insertion)</td><td>inserción en órbita marciana (IOM)</td><td>—</td><td>—</td><td>—</td><td>—</td><td>ESA Spanish</td></tr><tr><td>EDL (entry, descent, landing)</td><td>EDA (entrada, descenso, aterrizaje)</td><td>—</td><td>—</td><td>—</td><td>—</td><td>NASA-JPL Spanish</td></tr><tr><td>TLI (trans-lunar injection)</td><td>inyección translunar (ITL)</td><td>—</td><td>—</td><td>—</td><td>—</td><td>NASA-MSFC Spanish</td></tr><tr><td>TMI (trans-Mars injection)</td><td>inyección transmarciana (ITM)</td><td>—</td><td>—</td><td>—</td><td>—</td><td>ESA Spanish</td></tr><tr><td>TCM (trajectory correction manoeuvre)</td><td>maniobra de corrección de trayectoria (MCT)</td><td>—</td><td>—</td><td>—</td><td>—</td><td>NASA-JPL Spanish</td></tr><tr><td>splashdown</td><td>amerizaje</td><td>—</td><td>—</td><td>—</td><td>—</td><td>RAE</td></tr><tr><td>rendezvous</td><td>acoplamiento <em>(when docking)</em> / encuentro <em>(when proximity)</em></td><td>—</td><td>—</td><td>—</td><td>—</td><td>ESA Spanish</td></tr><tr><td>heliocentric</td><td>heliocéntrico</td><td>—</td><td>—</td><td>—</td><td>—</td><td>RAE</td></tr><tr><td>cislunar</td><td>cislunar</td><td>—</td><td>—</td><td>—</td><td>—</td><td>NASA-MSFC Spanish</td></tr></tbody></table><hr><h2 id="§5-tone-register-guidance" tabindex="-1">§5 Tone + register guidance <a class="header-anchor" href="#§5-tone-register-guidance" aria-label="Permalink to &quot;§5 Tone + register guidance&quot;">​</a></h2><ul><li><strong>Educational, friendly, precise.</strong> Orrery is for the curious learner first; physics accuracy second. Translations should match that register.</li><li><strong>Informal &quot;you&quot; where the language distinguishes</strong> (Spanish <code>tú</code>, French <code>tu</code>, German <code>du</code>). The English source uses friendly direct address.</li><li><strong>Active voice</strong> preferred over passive where the language allows naturally.</li><li><strong>Concise</strong> — Spanish runs ~30% longer than English; tighten where possible to avoid layout overflow at 375px.</li><li><strong>Date formatting</strong> is handled by <code>Intl.DateTimeFormat</code> (locale-aware). Do not translate dates in strings.</li><li><strong>Number formatting</strong> handled by <code>Intl.NumberFormat</code>. Do not translate numbers in strings.</li></ul><hr><h2 id="§6-source-authorities" tabindex="-1">§6 Source authorities <a class="header-anchor" href="#§6-source-authorities" aria-label="Permalink to &quot;§6 Source authorities&quot;">​</a></h2><p>When a term is contested, defer in this order:</p><ol><li><strong>The space agency&#39;s own glossary</strong> in the target language (ESA Spanish, NASA-JPL Spanish, JAXA Japanese, CNSA Mandarin, etc.).</li><li><strong>The country&#39;s national language academy</strong> for general scientific vocabulary (RAE for Spanish, Académie française for French, Duden for German, Crusca for Italian, Academia Brasileira de Letras for pt-BR).</li><li><strong>Wikipedia in the target language</strong> as a tertiary tie-breaker — useful for confirming widespread usage but not authoritative.</li><li><strong>LLM judgement</strong> as final fallback when no authority exists. Document the choice in a comment and surface for review.</li></ol><p>Cited source links (populate per language as glossaries are consulted):</p><ul><li>ESA Spanish glossary: <code>https://www.esa.int/Space_in_Member_States/Spain</code> (general portal; search for &quot;glosario&quot;)</li><li>NASA-MSFC Spanish technical reports: NTRS search by <code>language:Spanish</code></li><li>NASA-JPL Spanish-language editorial guidelines: internal; cite via the specific PDF when quoted</li><li>IAU resolutions on astronomical unit: <code>https://www.iau.org/static/resolutions/IAU2012_English.pdf</code></li><li>RAE diccionario: <code>https://dle.rae.es/</code></li></ul><hr><h2 id="§7-what-to-do-when-stuck" tabindex="-1">§7 What to do when stuck <a class="header-anchor" href="#§7-what-to-do-when-stuck" aria-label="Permalink to &quot;§7 What to do when stuck&quot;">​</a></h2><ul><li><strong>Term not in this glossary.</strong> Translate per language convention; add a row to §3 or §4 with the chosen term and a citation.</li><li><strong>Conflicting conventions across sources.</strong> Pick the agency glossary over the language academy; document the conflict in a one-line note.</li><li><strong>English term has no equivalent.</strong> Keep the English term and add an inline gloss on first use (e.g. <code>porkchop plot</code> in Spanish editorial prose).</li><li><strong>Mission name conflict</strong> (e.g. agency uses one romanisation, Wikipedia uses another). Defer to the agency&#39;s official romanisation.</li></ul>',44)])])}const p=e(n,[["render",o]]);export{g as __pageData,p as default};
